    if user.role not in discounts:
        raise ValueError("Invalid user role")

    # Calculate the discount percentage
    discount_percentage = discounts[user.role]

    # Calculate the total cart value
    total_cart_value = sum(item['price'] * item['quantity'] for item in cart_items)

    # Apply the discount to the cart total
    discounted_total = total_cart_value - (total_cart_value * discount_percentage)

